  public void _jspService(final javax.servlet.http.HttpServletRequest request, final javax.servlet.http.HttpServletResponse response)
      throws java.io.IOException, javax.servlet.ServletException {

    final java.lang.String _jspx_method = request.getMethod();
    if (!"GET".equals(_jspx_method) && !"POST".equals(_jspx_method) && !"HEAD".equals(_jspx_method) && !javax.servlet.DispatcherType.ERROR.equals(request.getDispatcherType())) {
      response.sendError(HttpServletResponse.SC_METHOD_NOT_ALLOWED, "JSPs only permit GET POST or HEAD");
      return;
    }

    final javax.servlet.jsp.PageContext pageContext;
    javax.servlet.http.HttpSession session = null;
    final javax.servlet.ServletContext application;
    final javax.servlet.ServletConfig config;
    javax.servlet.jsp.JspWriter out = null;
    final java.lang.Object page = this;
    javax.servlet.jsp.JspWriter _jspx_out = null;
    javax.servlet.jsp.PageContext _jspx_page_context = null;


    try {
      response.setContentType("text/html; charset=UTF-8");
      pageContext = _jspxFactory.getPageContext(this, request, response,
      			null, true, 8192, true);
      _jspx_page_context = pageContext;
      application = pageContext.getServletContext();
      config = pageContext.getServletConfig();
      session = pageContext.getSession();
      out = pageContext.getOut();
      _jspx_out = out;


    String apname = request.getParameter("a");
    if (apname == null) return;

    User user = (User) session.getAttribute("USER");
    RagicBundle bundle = (RagicBundle) session.getAttribute("RAGIC_BUNDLE");

    String singleID = request.getParameter("id");
    if (singleID == null) return;

    SimpleDateFormat sdf = new SimpleDateFormat("yyyy/MM/dd HH:mm:ss");

    APIQuery uploadQ = new APIQuery(apname, PATH_CUSTOM, CUSTOM_SHEET_INDEX);
    uploadQ.setBundle(bundle);
    uploadQ.setUpdateMode();
    APIEntry uploadEntry = uploadQ.getAPIEntry(Encoder.parseInt(singleID));
    uploadEntry.setIgnoreEmptyCheck(true);
    uploadEntry.setSendNotification(false);
    uploadEntry.setCreateHistory(false);
    uploadEntry.setRecalParentEntryFormula(false);

    boolean firstImport = uploadEntry.getFieldValue(UPLOAD_STATUS).isEmpty();

    String fileName = uploadEntry.getFieldValue(UPLOAD_FILE);
    if (fileName.length() == 0) {
        out.println("請選擇檔案");
        saveErrorStatus(uploadEntry, "請選擇正確的檔案", user, bundle);
        return;
    }


    Workbook wb = null;
    try {
        InputStream input = new FileInputStream("cust/data/" + apname + "/upload/" + fileName);
        wb = WorkbookFactory.create(input);
    } catch (IOException | EncryptedDocumentException e) {
        saveErrorStatus(uploadEntry, "請選擇正確的檔案", user, bundle);
        return;
    }

    logImport("Date:"+sdf.format(Calendar.getInstance().getTime()));
    logImport("File Name:"+fileName);

    BDBMgr mgr = BDBMgr.getInstance(apname);

    Sheet sheet = wb.getSheetAt(0);
    int lastRowNum = sheet.getLastRowNum(),
        dataNumsCount = 0,
        failCount = 0;
    String failReason = "";
    for (int i = 1; i <= lastRowNum; i++) {
        Row row = sheet.getRow(i);
        if (row == null) continue;
        dataNumsCount++;

        String importId = getCellValue(row.getCell(0)),
                exportStatus = getCellValue(row.getCell(1)),
                account = getCellValue(row.getCell(2)),
                processStatus = getCellValue(row.getCell(4));

        Date payDate = null;
        DataFormat df = wb.createDataFormat();
        CellStyle dateStyle = wb.createCellStyle();
        dateStyle.setDataFormat(df.getFormat("yyyy/MM/dd hh:mm:ss"));
        Cell dateCell = row.getCell(3);
        if (dateCell != null) {
            dateCell.setCellStyle(dateStyle);
            payDate = Encoder.parseDate(getCellValue(dateCell));
        }
        String parsedPayDate = "";
        Calendar payday = Calendar.getInstance();
        if (payDate != null) {
            payday.setTime(payDate);
            parsedPayDate = sdf.format(payday.getTime());
        }

        String[] filters = new String[1];
        filters[0] = IMPORT_ID + "|" + NUIFilter.OPERAND_EQ + "|" + importId;

        // 查詢 "已撥款案件" 以判斷是不是重複匯入
        APIQuery allocatedQ = new APIQuery(apname, PATH_ALLOCATED, ALLOCATED_SHEET_INDEX);
        APIEntry allocatedE = null;
        allocatedQ.setBundle(bundle);
        allocatedQ.setUpdateMode();
        allocatedQ.setFiltersStringV2(filters);
        if (!firstImport) {
            EntryLocker lock = mgr.lockSheet(allocatedQ.getPath(), allocatedQ.getForm().getFormName(), user, EntryLocker.UNKNOWN);
            if (lock == null) {
                APIResults ar = allocatedQ.getAPIResults();
                Iterator<APIEntry> ite = ar.iterator(allocatedQ.getForm());
                if (ite.hasNext()) {
                    allocatedE = ite.next();
                }
                mgr.unlockSheet(allocatedQ.getPath(), allocatedQ.getForm().getFormName());
            } else {
                failCount++;
                failReason += "已撥款案件表單鎖定中，略過案件編號(才將)" + importId + "\r\n";
                continue;
            }
        }

        // fetch entry with the same 案件編號(才將) from "核准待撥款案件"
        if (allocatedE == null) {
            APIQuery importQ = new APIQuery(apname, PATH_IMPORT, IMPORT_SHEET_INDEX);
            importQ.addFetchDomains(IMPORT_ID);
            importQ.addFetchDomains(EXPORT_STATUS);
            importQ.addFetchDomains(ACCOUNT);
            importQ.addFetchDomains(PAY_DATE);
            importQ.addFetchDomains(PROCESS_STATUS);
            importQ.setBundle(bundle);
            importQ.setUpdateMode();
            importQ.setFiltersStringV2(filters);

            EntryLocker lock = mgr.lockSheet(importQ.getPath(), importQ.getForm().getFormName(), user, EntryLocker.UNKNOWN);
            if (lock == null) {
                APIResults ar = importQ.getAPIResults();
                Iterator<APIEntry> ite = ar.iterator(importQ.getForm());
                if (ite.hasNext() && payDate != null
                        && exportStatus.length() > 0 && account.length() > 0 && processStatus.length() > 0) {
                    APIEntry e = ite.next();
                    e.setFieldValue(EXPORT_STATUS, exportStatus);
                    e.setFieldValue(ACCOUNT, account);
                    e.setFieldValue(PAY_DATE, parsedPayDate);
                    e.setFieldValue(PROCESS_STATUS, processStatus);
                    e.setIgnoreEmptyCheck(true);
                    e.setSendNotification(false);
                    e.setCreateHistory(false);
                    e.setExecuteWorkflow(false);
                    e.setRecalParentEntryFormula(false);
                    ScriptResponse importRes = e.save(user, bundle);
                    if(!importRes.ifExec()){
                        failCount++;
                        failReason += "案件編號" + importId + " 核准待撥款案件 " + importRes.getMessage() + "\r\n";
                        continue;
                    } else {
                        logImport("line:"+dataNumsCount+", 核准待撥款案件:"+e.getJSON());
                    }
                } else {
                    failCount++;
                    failReason += "案件編號 " + importId + "無資料或填寫不完全\r\n";
                }

                mgr.unlockSheet(importQ.getPath(), importQ.getForm().getFormName());
            } else {
                failCount++;
                failReason += "核准待撥款案件表單鎖定中，略過案件編號" + importId + "\r\n";
                continue;
            }
        }

        // fetch entry from "已撥款案件" and then create "本息表".
        EntryLocker lock = mgr.lockSheet(allocatedQ.getPath(), allocatedQ.getForm().getFormName(), user, EntryLocker.UNKNOWN);
        if (lock == null) {
            if (allocatedE == null) {
                allocatedQ.resetData();
                APIResults ar = allocatedQ.getAPIResults();
                Iterator<APIEntry> ite = ar.iterator(allocatedQ.getForm());
                if (ite.hasNext()) {
                    allocatedE = ite.next();
                } else {
                    failCount++;
                    failReason += "已撥款案件查無案件編號 " + importId + "\r\n";
                    continue;
                }
            }

            int periods = Encoder.parseInt(allocatedE.getFieldValue(PERIODS));
            String periodAmount = allocatedE.getFieldValue(PERIOD_AMOUNT);
            String lastPeriodAmount = allocatedE.getFieldValue(LAST_PERIOD_AMOUNT);
            int existRecords = allocatedE.getSubtableSize(INTEREST_SUBTABLE_KEY);

            int DayofToday = payday.get(Calendar.DAY_OF_MONTH);

            for (int ai = 1; ai <= periods; ai++) {
                int insertRowIndex = (ai > existRecords ? -1 : 1) * ai;
                allocatedE.setSubtableFieldValue(INTEREST_PERIODS, insertRowIndex, String.valueOf(ai));
                if (ai < periods) {
                    allocatedE.setSubtableFieldValue(PAYABLE_AMOUNT, insertRowIndex, periodAmount);
                } else {
                    allocatedE.setSubtableFieldValue(PAYABLE_AMOUNT, insertRowIndex, lastPeriodAmount);
                }


                Calendar cal = Calendar.getInstance();
                if (payDate != null) {
                    cal.setTime(payDate);
                }
                cal.add(Calendar.MONTH, ai);
                cal.set(Calendar.DAY_OF_MONTH, Math.min(DayofToday, cal.getActualMaximum(Calendar.DAY_OF_MONTH)));

                allocatedE.setSubtableFieldValue(PAYABLE_DATE, insertRowIndex, sdf.format(cal.getTime()));
            }
            allocatedE.setIgnoreEmptyCheck(true);
            allocatedE.setSendNotification(false);
            allocatedE.setCreateHistory(false);
            allocatedE.setExecuteWorkflow(false);
            allocatedE.setRecalParentEntryFormula(false);
            ScriptResponse sr = allocatedE.save(user, bundle);
            if(!sr.ifExec()){
                failCount++;
                failReason += "案件編號" + importId + " 已撥款案件 " + sr.getMessage() + "\r\n";
                continue;
            } else {
                logImport("line:"+dataNumsCount+", 已撥款案件:"+allocatedE.getJSON());
            }

            mgr.unlockSheet(allocatedQ.getPath(), allocatedQ.getForm().getFormName());
        } else {
            failCount++;
            failReason += "已撥款案件表單鎖定中，略過案件編號" + importId + "\r\n";
            continue;
        }


        APIQuery writeOffQ = new APIQuery(apname, PATH_WRITEOFF, WRITEOFF_SHEET_INDEX);
        writeOffQ.setBundle(bundle);
        writeOffQ.setUpdateMode();
        lock = mgr.lockSheet(writeOffQ.getPath(), writeOffQ.getForm().getFormName(), user, EntryLocker.UNKNOWN);
        if (lock == null) {
            APIEntry writeOffE = writeOffQ.getAPIEntry(allocatedE.getRootNodeId());
            if (writeOffE != null) {
                writeOffE.recalculateFormula(1000396);
                writeOffE.setIgnoreEmptyCheck(true);
                writeOffE.setSendNotification(false);
                writeOffE.setCreateHistory(false);
                writeOffE.setExecuteWorkflow(false);
                writeOffE.setRecalParentEntryFormula(false);
                ScriptResponse sr = writeOffE.save(user, bundle);
                if(!sr.ifExec()){
                    failCount++;
                    failReason += "案件編號" + importId + " 催收案件 " + sr.getMessage() + "\r\n";
                    continue;
                } else {
                    logImport("line:"+dataNumsCount+", 催收案件:"+writeOffE.getJSON());
                }
            }
            mgr.unlockSheet(writeOffQ.getPath(), writeOffQ.getForm().getFormName());
        } else {
            failReason += "催收案件鎖定中，案件編號" + importId + "公式重算失敗\r\n";
        }

        // create backup records
        APIQuery mappingQ = new APIQuery(apname, PATH_MAPPING, SHEET_MAPPING_INDEX);
        APIEntry mappingEntry;
        mappingQ.setBundle(bundle);
        mappingQ.setUpdateMode();
        filters[0] =  "1002855|" + NUIFilter.OPERAND_EQ + "|" + account;
        mappingQ.setFiltersStringV2(filters);
        lock = mgr.lockSheet(mappingQ.getPath(), mappingQ.getForm().getFormName(), user, EntryLocker.UNKNOWN);
        if (lock == null) {
            APIResults mappingAr = mappingQ.getAPIResults();
            Iterator<APIEntry> mi = mappingAr.iterator(mappingQ.getForm());
            if (mi.hasNext()) {
                mappingEntry = mi.next();
            } else {
                mappingEntry = mappingQ.insertAPIEntry();
            }

            mappingEntry.setFieldValue(1002855, account);
            mappingEntry.setFieldValue(1002782, importId);
            mappingEntry.setFieldValue(1002784, parsedPayDate);
            mappingEntry.setFieldValue(1002787, allocatedE.getFieldValue(1000096));
            mappingEntry.setFieldValue(1002792, allocatedE.getFieldValue(1000272));
            mappingEntry.setFieldValue(1002783, allocatedE.getFieldValue(PERIODS));
            mappingEntry.setFieldValue(1002851, allocatedE.getFieldValue(PERIOD_AMOUNT));
            mappingEntry.setFieldValue(1002852, allocatedE.getFieldValue(LAST_PERIOD_AMOUNT));
            mappingEntry.setFieldValue(1002796, allocatedE.getFieldValue(1000001));
            mappingEntry.setFieldValue(1002797, allocatedE.getFieldValue(1000005));
            mappingEntry.setFieldValue(1002788, allocatedE.getFieldValue(1000084));
            mappingEntry.setFieldValue(1002789, allocatedE.getFieldValue(1000084));
            mappingEntry.setIgnoreEmptyCheck(true);
            mappingEntry.setSendNotification(false);
            mappingEntry.setCreateHistory(false);
            mappingEntry.setExecuteWorkflow(false);
            mappingEntry.setRecalParentEntryFormula(false);
            mappingEntry.save(user, bundle);

            mgr.unlockSheet(mappingQ.getPath(), mappingQ.getForm().getFormName());
        } else {
            failReason += "額外撥款紀錄鎖定中，案件編號" + importId + "紀錄失敗\r\n";
        }
    }

    uploadEntry.setFieldValue(UPLOAD_STATUS, "Y");
    uploadEntry.setFieldValue(FAIL_REASON, failReason);
    uploadEntry.setFieldValue(TOTAL_DATA_COUNT, String.valueOf(dataNumsCount));
    uploadEntry.setFieldValue(SUCESS_COUNT, String.valueOf(dataNumsCount - failCount));
    uploadEntry.setFieldValue(FAIL_COUNT, String.valueOf(failCount));
    uploadEntry.save(user, bundle);

    // close window when all actions are done.
    out.print("<script>opener.document.getElementById('bReload').click();window.close();</script>");

    } catch (java.lang.Throwable t) {
      if (!(t instanceof javax.servlet.jsp.SkipPageException)){
        out = _jspx_out;
        if (out != null && out.getBufferSize() != 0)
          try {
            if (response.isCommitted()) {
              out.flush();
            } else {
              out.clearBuffer();
            }
          } catch (java.io.IOException e) {}
        if (_jspx_page_context != null) _jspx_page_context.handlePageException(t);
        else throw new ServletException(t);
      }
    } finally {
      _jspxFactory.releasePageContext(_jspx_page_context);
    }
  }
